import{_ as o,o as a,c as e,ag as r}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Data Import & Export","description":"","frontmatter":{},"headers":[],"relativePath":"account/data.md","filePath":"account/data.md"}'),i={name:"account/data.md"};function s(l,t,n,d,p,m){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="data-import-export" tabindex="-1">Data Import &amp; Export <a class="header-anchor" href="#data-import-export" aria-label="Permalink to &quot;Data Import &amp; Export&quot;">​</a></h1><p>Import existing data into MyCompanyDesk and export your records for backup or use in other tools.</p><h2 id="import" tabindex="-1">Import <a class="header-anchor" href="#import" aria-label="Permalink to &quot;Import&quot;">​</a></h2><h3 id="csv-import" tabindex="-1">CSV import <a class="header-anchor" href="#csv-import" aria-label="Permalink to &quot;CSV import&quot;">​</a></h3><p>Import data from CSV files for:</p><ul><li><strong>Customers</strong> — Name, email, phone, address, VAT number</li><li><strong>Invoices</strong> — Invoice details with line items</li><li><strong>Expenses</strong> — Expense records with categories</li><li><strong>Projects</strong> — Project names and details</li><li><strong>Objects</strong> — Asset records</li></ul><h3 id="how-to-import" tabindex="-1">How to import <a class="header-anchor" href="#how-to-import" aria-label="Permalink to &quot;How to import&quot;">​</a></h3><ol><li>Go to <strong>Profile &gt; Import</strong></li><li>Select the <strong>data type</strong> you want to import</li><li>Upload your <strong>CSV file</strong></li><li><strong>Map columns</strong> — Match your CSV column headers to MyCompanyDesk fields</li><li><strong>Preview</strong> — Review the data before importing</li><li><strong>Confirm</strong> — Click Import to create the records</li></ol><h3 id="import-tips" tabindex="-1">Import tips <a class="header-anchor" href="#import-tips" aria-label="Permalink to &quot;Import tips&quot;">​</a></h3><ul><li>Use UTF-8 encoding for your CSV files</li><li>Include a header row with column names</li><li>Date formats should be consistent (YYYY-MM-DD recommended)</li><li>Amount fields should use dot (.) as decimal separator</li><li>Empty fields are skipped (existing defaults are used)</li></ul><h3 id="column-mapping" tabindex="-1">Column mapping <a class="header-anchor" href="#column-mapping" aria-label="Permalink to &quot;Column mapping&quot;">​</a></h3><p>The import wizard shows your CSV columns and lets you map each to the corresponding MyCompanyDesk field. Common mappings:</p><table tabindex="0"><thead><tr><th>CSV column</th><th>Maps to</th></tr></thead><tbody><tr><td>Company Name / Name</td><td>Customer name</td></tr><tr><td>Email</td><td>Customer email</td></tr><tr><td>Street / Address</td><td>Street address</td></tr><tr><td>ZIP / Postal Code</td><td>Postal code</td></tr><tr><td>City</td><td>City</td></tr><tr><td>VAT / BTW</td><td>VAT number</td></tr><tr><td>Phone</td><td>Phone number</td></tr></tbody></table><h2 id="export" tabindex="-1">Export <a class="header-anchor" href="#export" aria-label="Permalink to &quot;Export&quot;">​</a></h2><h3 id="csv-export" tabindex="-1">CSV export <a class="header-anchor" href="#csv-export" aria-label="Permalink to &quot;CSV export&quot;">​</a></h3><p>Export your data as CSV from the respective list pages:</p><ul><li><strong>Invoices</strong> — All invoices with amounts, dates, statuses</li><li><strong>Expenses</strong> — All expenses with categories and amounts</li><li><strong>Customers</strong> — Your customer database</li></ul><p>Click the <strong>Export</strong> button on the list page to download.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>CSV export requires the <strong>Pro</strong> plan or higher.</p></div><h3 id="gdpr-data-export" tabindex="-1">GDPR data export <a class="header-anchor" href="#gdpr-data-export" aria-label="Permalink to &quot;GDPR data export&quot;">​</a></h3><p>Export all your personal data in JSON format:</p><ol><li>Go to <strong>Profile &gt; Data</strong></li><li>Click <strong>Export My Data</strong></li><li>Download the JSON file containing all your account data</li></ol><p>This GDPR export includes:</p><ul><li>Your profile information</li><li>All invoices, expenses, quotes</li><li>Customer records</li><li>Project and time data</li><li>Settings and preferences</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Export your data regularly as a backup</li><li>Use CSV export to share data with your accountant</li><li>When switching from another tool, use the import wizard to migrate your customer list</li><li>The GDPR export provides a complete snapshot of your data</li></ul>',26)])])}const u=o(i,[["render",s]]);export{h as __pageData,u as default};
